arguments.file_text:
@page "/chat"
@using sv_c0530cdbfcb8454998000ac10fe9237f.Services
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Team Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    SelectedChannelId="selectedChannel?.Id"
                    OnChannelSelected="SelectChannelAsync" />

    <MessageArea Channel="selectedChannel"
                 Messages="messages"
                 ThreadSummaries="threadSummaries"
                 IsThreadOpen="isThreadOpen"
                 IsLoadingMore="isLoadingMore"
                 HasMoreMessages="hasMoreMessages"
                 OnSendMessage="SendMessageAsync"
                 OnOpenThread="OpenThreadAsync"
                 OnReact="ReactAsync"
                 OnLoadMore="LoadMoreMessagesAsync" />

    @if (isThreadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnSendReply="SendThreadReplyAsync"
                     OnClose="CloseThread" />
    }
</div>

@code {
    private List<Channel> channels = new();
    private Channel? selectedChannel;
    private List<Message> messages = new();
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();
    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0].Id);
        }
    }

    private async Task SelectChannelAsync(int channelId)
    {
        var channel = channels.FirstOrDefault(c => c.Id == channelId);
        if (channel is null) return;

        selectedChannel = channel;
        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        hasMoreMessages = messages.Count >= PageSize;
        BuildThreadSummaries();
        CloseThread();
        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessagesAsync()
    {
        if (selectedChannel is null || isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        hasMoreMessages = older.Count >= PageSize;
        messages.InsertRange(0, older);
        BuildThreadSummaries();

        isLoadingMore = false;
    }

    private async Task SendMessageAsync(string content)
    {
        if (selectedChannel is null || string.IsNullOrWhiteSpace(content)) return;

        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(msg);
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (threadRootMessage is null || selectedChannel is null || string.IsNullOrWhiteSpace(content)) return;

        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update the thread summary in the main view
        BuildThreadSummaries();
    }

    private async Task ReactAsync((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to reflect new reaction
        if (selectedChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, messages.Count);
        }
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        // Group reply messages by their ReplyToId to build summaries
        var replies = messages.Where(m => m.ReplyToId is not null).GroupBy(m => m.ReplyToId!.Value);
        foreach (var group in replies)
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

@using sv_c0530cdbfcb8454998000ac10fe9237f.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name"># @channel.Name</div>
                <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                @if (channel.UnreadCount > 0)
                {
                    <span class="unread-badge">@channel.UnreadCount</span>
                }
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string desc)
        => desc.Length > 50 ? desc[..47] + "..." : desc;
}

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #1a1d21;
    color: #ccc;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #333;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #333;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 10px 16px;
    cursor: pointer;
