+        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
+        isThreadOpen = true;
+    }
+
+    private async Task SendThreadReplyAsync(string content)
+    {
+        if (threadRootMessage is null || selectedChannel is null || string.IsNullOrWhiteSpace(content)) return;
+
+        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
+        threadReplies.Add(reply);
+
+        // Update the thread summary in the main view
+        BuildThreadSummaries();
+    }
+
+    private async Task ReactAsync((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+
+        // Refresh messages to reflect new reaction
+        if (selectedChannel is not null)
+        {
+            messages = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, messages.Count);
+        }
+    }
+
+    private void CloseThread()
+    {
+        isThreadOpen = false;
+        threadRootMessage = null;
+        threadReplies.Clear();
+    }
+
+    private void BuildThreadSummaries()
+    {
+        threadSummaries.Clear();
+        // Group reply messages by their ReplyToId to build summaries
+        var replies = messages.Where(m => m.ReplyToId is not null).GroupBy(m => m.ReplyToId!.Value);
+        foreach (var group in replies)
+        {
+            threadSummaries[group.Key] = new ThreadSummary(
+                group.Key,
+                group.Count(),
+                group.Max(m => m.SentAt)
+            );
+        }
+    }
+}
