@using sv_c0530cdbfcb8454998000ac10fe9237f.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name"># @channel.Name</div>
                <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                @if (channel.UnreadCount > 0)
                {
                    <span class="unread-badge">@channel.UnreadCount</span>
                }
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string desc)
        => desc.Length > 50 ? desc[..47] + "..." : desc;
}

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #1a1d21;
    color: #ccc;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #333;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #333;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 10px 16px;
    cursor: pointer;
    position: relative;
    border-left: 3px solid transparent;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #26292e;
}

.channel-item.active {
    background: #1164a3;
    border-left-color: #fff;
    color: #fff;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.channel-desc {
    font-size: 0.75rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-desc {
    color: #cde;
}

.unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

