arguments.file_text:
@using sv_c0530cdbfcb8454998000ac10fe9237f.Services

<div class="message-area @(IsThreadOpen ? "with-thread" : "")">
    @if (Channel is not null)
    {
        <div class="area-header">
            <h2># @Channel.Name</h2>
            <span class="header-desc">@Channel.Description</span>
        </div>

        <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @if (HasMoreMessages)
            {
                <button class="load-more-btn" @onclick="OnLoadMore">Load older messages</button>
            }

            @foreach (var msg in Messages.Where(m => m.ReplyToId is null))
            {
                ThreadSummaries.TryGetValue(msg.Id, out var summary);
                <MessageItem Message="msg"
                             ThreadSummary="summary"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <div class="message-input">
            <textarea @bind="newMessage"
                      @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Message #@Channel.Name"
                      rows="2"></textarea>
            <button class="send-btn" @onclick="SendAsync" disabled="@string.IsNullOrWhiteSpace(newMessage)">
                Send
            </button>
        </div>
    }
    else
    {
        <div class="no-channel">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsThreadOpen { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private string newMessage = "";
    private ElementReference messageListRef;

    private async Task SendAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessage)) return;
        var content = newMessage;
        newMessage = "";
        await OnSendMessage.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendAsync();
        }
    }

    private async Task HandleScroll()
    {
        // The scroll-to-top load-more is handled via the button for reliability.
        // A JS interop approach could detect scrollTop === 0 for auto-loading.
        await Task.CompletedTask;
    }
}

.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #fff;
    min-width: 0;
}

.message-area.with-thread {
    max-width: 55%;
}

.area-header {
    padding: 14px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
}

.area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
}

.header-desc {
    font-size: 0.8rem;
    color: #666;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 10px;
    color: #888;
    font-size: 0.85rem;
}

.load-more-btn {
    display: block;
    margin: 8px auto;
    padding: 6px 16px;
    border: 1px solid #ddd;
    border-radius: 6px;
    background: #f8f8f8;
    cursor: pointer;
    font-size: 0.8rem;
    color: #555;
}

.load-more-btn:hover {
    background: #eee;
}

.message-input {
    display: flex;
    gap: 10px;
    padding: 12px 20px;
    border-top: 1px solid #e0e0e0;
    background: #fafafa;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 10px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.2s;
}

.message-input textarea:focus {
    border-color: #1264a3;
}

.send-btn {
    padding: 10px 20px;
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background 0.2s;
}

.send-btn:hover:not(:disabled) {
    background: #005e44;
}

.send-btn:disabled {
    background: #aaa;
    cursor: default;
}

.no-channel {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #888;
    font-size: 1.1rem;
}

@using sv_c0530cdbfcb8454998000ac10fe9237f.Services

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="msg-header">
        <span class="msg-author">@Message.Author</span>
        <span class="msg-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="msg-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="msg-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
            &middot; last @FormatRelativeTime(ThreadSummary.LastReplyAt)
        </button>
    }

    @if (showActions)
    {
        <div class="msg-actions">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
                💬 Reply
            </button>
            <div class="emoji-picker">
                @foreach (var emoji in commonEmojis)
                {
                    <button class="emoji-btn" @onclick="() => OnReact.InvokeAsync((Message.Id, emoji))">
                        @emoji
                    </button>
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "👀", "🚀"];

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

