<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">&times;</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
            <div class="root-time">@RootMessage.SentAt.ToString("MMM d, h:mm tt")</div>
        </div>

        <div class="reply-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="reply-item">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <div class="reply-input">
            <textarea @bind="replyText"
                      @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Reply…"
                      rows="2"></textarea>
            <button class="reply-btn" @onclick="SendReplyAsync" disabled="@string.IsNullOrWhiteSpace(replyText)">
                Reply
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = new();
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }

    private string replyText = "";

    private async Task SendReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(replyText)) return;
        var content = replyText;
        replyText = "";
        await OnSendReply.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReplyAsync();
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}
