@using sv_c0530cdbfcb8454998000ac10fe9237f.Services

<div class="message-area @(IsThreadOpen ? "with-thread" : "")">
    @if (Channel is not null)
    {
        <div class="area-header">
            <h2># @Channel.Name</h2>
            <span class="header-desc">@Channel.Description</span>
        </div>

        <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @if (HasMoreMessages)
            {
                <button class="load-more-btn" @onclick="OnLoadMore">Load older messages</button>
            }

            @foreach (var msg in Messages.Where(m => m.ReplyToId is null))
            {
                ThreadSummaries.TryGetValue(msg.Id, out var summary);
                <MessageItem Message="msg"
                             ThreadSummary="summary"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <div class="message-input">
            <textarea @bind="newMessage"
                      @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Message #@Channel.Name"
                      rows="2"></textarea>
            <button class="send-btn" @onclick="SendAsync" disabled="@string.IsNullOrWhiteSpace(newMessage)">
                Send
            </button>
        </div>
    }
    else
    {
        <div class="no-channel">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsThreadOpen { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private string newMessage = "";
    private ElementReference messageListRef;

    private async Task SendAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessage)) return;
        var content = newMessage;
        newMessage = "";
        await OnSendMessage.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendAsync();
        }
    }

    private async Task HandleScroll()
    {
        // The scroll-to-top load-more is handled via the button for reliability.
        // A JS interop approach could detect scrollTop === 0 for auto-loading.
        await Task.CompletedTask;
    }
}

