toolArgs.file_text:
.message-item {
    padding: 8px 12px;
    border-radius: 6px;
    position: relative;
    margin-bottom: 4px;
    transition: background 0.15s;
}

.message-item:hover {
    background: #f5f5f5;
}

.msg-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.msg-author {
    font-weight: 700;
    font-size: 0.9rem;
}

.msg-time {
    font-size: 0.7rem;
    color: #888;
}

.msg-content {
    font-size: 0.9rem;
    line-height: 1.5;
    word-break: break-word;
}

.msg-reactions {
    display: flex;
    gap: 6px;
    margin-top: 6px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    border: 1px solid #ddd;
    border-radius: 12px;
    font-size: 0.8rem;
    background: #f0f0f0;
    cursor: default;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 0;
    border: none;
    background: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.msg-actions {
    position: absolute;
    top: -4px;
    right: 8px;
    display: flex;
    gap: 4px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    z-index: 10;
}

.action-btn {
    padding: 4px 10px;
    border: none;
    background: none;
    cursor: pointer;
    font-size: 0.8rem;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #e8e8e8;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    border-left: 1px solid #ddd;
    padding-left: 4px;
}

.emoji-btn {
    border: none;
    background: none;
    cursor: pointer;
    font-size: 1rem;
    padding: 2px 4px;
    border-radius: 4px;
}

.emoji-btn:hover {
    background: #e8e8e8;
}

