toolArgs.file_text:
.thread-panel {
    width: 25%;
    min-width: 280px;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #e0e0e0;
    background: #fff;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 14px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.4rem;
    cursor: pointer;
    color: #666;
    padding: 0 4px;
    line-height: 1;
}

.close-btn:hover {
    color: #000;
}

.thread-root {
    padding: 14px 16px;
    border-bottom: 1px solid #eee;
    background: #fafafa;
}

.root-author {
    font-weight: 700;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.root-content {
    font-size: 0.9rem;
    line-height: 1.4;
}

.root-time {
    font-size: 0.7rem;
    color: #888;
    margin-top: 4px;
}

.reply-divider {
    padding: 8px 16px;
    font-size: 0.75rem;
    color: #888;
    border-bottom: 1px solid #eee;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

.reply-item {
    padding: 8px 0;
    border-bottom: 1px solid #f0f0f0;
}

.reply-item:last-child {
    border-bottom: none;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.reply-time {
    font-size: 0.7rem;
    color: #888;
}

.reply-content {
    font-size: 0.85rem;
    line-height: 1.4;
}

.reply-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fafafa;
    align-items: flex-end;
}

.reply-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 10px;
    font-size: 0.85rem;
    font-family: inherit;
    outline: none;
}

.reply-input textarea:focus {
    border-color: #1264a3;
}

.reply-btn {
    padding: 8px 16px;
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.85rem;
}

.reply-btn:hover:not(:disabled) {
    background: #005e44;
}

.reply-btn:disabled {
    background: #aaa;
    cursor: default;
}

